fun solve(s: String): String {
    val result = mutableListOf<Char>()

    for (char in s) {
        if (char.isLowerCase()) {
            result.add(char)
        } else if (char == '*') {
            if (result.isNotEmpty()) {
                result.removeAt(result.size - 1)
            }
        } else if (char == '#') {
            result.addAll(result)
        } else if (char == '%') {
            result.reverse()
        }
    }

    return result.joinToString("")
}
