def solve(s: str) -> str:
    result = []

    for char in s:
        if char.islower():
            result.append(char)
        elif char == '*':
            if result:
                result.pop()
        elif char == '#':
            result += result[:]
        elif char == '%':
            result.reverse()

    return ''.join(result)
